#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
#define int ll
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int M=5e4+10,INF=0x3f3f3f3f3f3f3f3fll,N=210;
vector<vector<int>> G,IG,T;
int n,m,u[M],v[M],c[M],d[M],d1[N],dn[N],g1[N],gn[N],f1[N],fn[N],h1[N],hn[N],ans,dis[N],fa[N];bool vis[N];
inline void dij(int s,vector<vector<int>> &G,int *dis,int *fa)
{
	memset(dis,0x3f,(n+2)*sizeof(int));dis[s]=0;memset(vis,0,sizeof(vis));
	rep(1,n,tt)
	{
		int mn=INF,u=0;rep(1,n,i)if(!vis[i]&&dis[i]<mn)mn=dis[i],u=i;if(!u)break;vis[u]=true;
		rep(1,n,v)if(G[u][v]!=INF&&dis[v]>dis[u]+G[u][v])dis[v]=dis[fa[v]=u]+G[u][v];
	}
}
signed main()
{
	n=read();G.resize(n+1);IG.resize(n+1);T.resize(n+1);
	rep(1,n,i)
	{
		G[i].resize(n+1);IG[i].resize(n+1);T[i].resize(n+1);
		for(int &v:G[i])v=INF;for(int &v:IG[i])v=INF;for(int &v:T[i])v=INF;
	}
	m=read();rep(1,m,i)
	{
		u[i]=read();v[i]=read();c[i]=read();d[i]=read();
		if(c[i]<=G[u[i]][v[i]]){T[u[i]][v[i]]=G[u[i]][v[i]];G[u[i]][v[i]]=c[i];}
		else if(c[i]<T[u[i]][v[i]])T[u[i]][v[i]]=c[i];
		IG[v[i]][u[i]]=G[u[i]][v[i]]=min(G[u[i]][v[i]],c[i]);
	}
	dij(1,G,d1,f1);dij(n,G,dn,fn);dij(1,IG,g1,h1);dij(n,IG,gn,hn);
	ans=INF;ans=min(ans,d1[n]+dn[1]);
	rep(1,m,i)
	{
		int t1=G[u[i]][v[i]],t2=G[v[i]][u[i]],dl=INF,dr=INF;
		G[u[i]][v[i]]=T[u[i]][v[i]];
		G[v[i]][u[i]]=min(G[v[i]][u[i]],t1);
		if(f1[v[i]]==u[i]&&d1[u[i]]+c[i]==d1[v[i]])dij(1,G,dis,fa),dl=dis[n];
		else dl=min(d1[n],d1[v[i]]+c[i]+gn[u[i]]);
		if(fn[v[i]]==u[i]&&dn[u[i]]+c[i]==dn[v[i]])dij(n,G,dis,fa),dr=dis[1];
		else dr=min(dn[1],dn[v[i]]+c[i]+g1[u[i]]);
		ans=min(ans,dl+dr+d[i]);G[u[i]][v[i]]=t1;G[v[i]][u[i]]=t2;
	}
	printf("%lld\n",ans==INF?-1:ans);return 0;
}
